// Hand-written queries (NOT generated by sqlc).
//
// sqlc is not available in this environment, so workspace-scoped task list
// queries live here, written to match the generated code style: a const SQL
// string, a Params struct, and a method on *Queries using the DBTX interface.

package db

import (
	"context"

	"github.com/jackc/pgx/v5/pgtype"
)

const listWorkspaceTasks = `-- name: ListWorkspaceTasks :many
SELECT atq.id, atq.agent_id, atq.issue_id, atq.status, atq.priority,
       atq.dispatched_at, atq.started_at, atq.completed_at, atq.result, atq.error,
       atq.created_at, atq.context, atq.runtime_id, atq.session_id, atq.work_dir,
       atq.trigger_comment_id, atq.chat_session_id, atq.autopilot_run_id,
       atq.attempt, atq.max_attempts, atq.parent_task_id, atq.failure_reason,
       atq.trigger_summary, atq.force_fresh_session,
       i.number AS issue_number
FROM agent_task_queue atq
JOIN agent a ON a.id = atq.agent_id
LEFT JOIN issue i ON i.id = atq.issue_id
WHERE a.workspace_id = $1
  AND ($2::text[] IS NULL OR atq.status = ANY($2::text[]))
  AND ($3::uuid IS NULL OR atq.agent_id = $3)
  AND ($4::uuid IS NULL OR atq.issue_id = $4)
ORDER BY atq.created_at DESC
LIMIT $5 OFFSET $6
`

type ListWorkspaceTasksParams struct {
	WorkspaceID pgtype.UUID
	Statuses    []string
	AgentID     pgtype.UUID
	IssueID     pgtype.UUID
	Limit       int32
	Offset      int32
}

// ListWorkspaceTasksRow is one agent_task_queue row plus the linked issue's
// number (NULL for tasks with no issue) so callers can render the issue key
// without an N+1 lookup.
type ListWorkspaceTasksRow struct {
	AgentTaskQueue
	IssueNumber pgtype.Int4
}

// ListWorkspaceTasks returns task rows for a workspace, newest first. The
// workspace is reached through the task's agent because agent_task_queue has
// no workspace_id column of its own.
func (q *Queries) ListWorkspaceTasks(ctx context.Context, arg ListWorkspaceTasksParams) ([]ListWorkspaceTasksRow, error) {
	rows, err := q.db.Query(ctx, listWorkspaceTasks,
		arg.WorkspaceID,
		arg.Statuses,
		arg.AgentID,
		arg.IssueID,
		arg.Limit,
		arg.Offset,
	)
	if err != nil {
		return nil, err
	}
	defer rows.Close()
	items := []ListWorkspaceTasksRow{}
	for rows.Next() {
		var i ListWorkspaceTasksRow
		if err := rows.Scan(
			&i.ID,
			&i.AgentID,
			&i.IssueID,
			&i.Status,
			&i.Priority,
			&i.DispatchedAt,
			&i.StartedAt,
			&i.CompletedAt,
			&i.Result,
			&i.Error,
			&i.CreatedAt,
			&i.Context,
			&i.RuntimeID,
			&i.SessionID,
			&i.WorkDir,
			&i.TriggerCommentID,
			&i.ChatSessionID,
			&i.AutopilotRunID,
			&i.Attempt,
			&i.MaxAttempts,
			&i.ParentTaskID,
			&i.FailureReason,
			&i.TriggerSummary,
			&i.ForceFreshSession,
			&i.IssueNumber,
		); err != nil {
			return nil, err
		}
		items = append(items, i)
	}
	if err := rows.Err(); err != nil {
		return nil, err
	}
	return items, nil
}

const countWorkspaceTasks = `-- name: CountWorkspaceTasks :one
SELECT count(*)
FROM agent_task_queue atq
JOIN agent a ON a.id = atq.agent_id
WHERE a.workspace_id = $1
  AND ($2::text[] IS NULL OR atq.status = ANY($2::text[]))
  AND ($3::uuid IS NULL OR atq.agent_id = $3)
  AND ($4::uuid IS NULL OR atq.issue_id = $4)
`

type CountWorkspaceTasksParams struct {
	WorkspaceID pgtype.UUID
	Statuses    []string
	AgentID     pgtype.UUID
	IssueID     pgtype.UUID
}

// CountWorkspaceTasks returns the total number of tasks matching the
// ListWorkspaceTasks filters (ignoring limit/offset) for pagination metadata.
func (q *Queries) CountWorkspaceTasks(ctx context.Context, arg CountWorkspaceTasksParams) (int64, error) {
	row := q.db.QueryRow(ctx, countWorkspaceTasks,
		arg.WorkspaceID,
		arg.Statuses,
		arg.AgentID,
		arg.IssueID,
	)
	var count int64
	err := row.Scan(&count)
	return count, err
}
